"use client";

import { useEffect, useRef, useState } from "react";
import { StudyBuild } from "./StudyBuild";
import "./study.css";

/**
 * Study · Conversation — the thinking medium (study spec §4.1).
 *
 * One surface, two states:
 *   - COLD OPEN (the grand hall): greeting + centered input, no messages.
 *   - THREAD: slim topbar + centered 740px stream + docked composer.
 * Sending from the cold open transitions (cross-fade) into the thread.
 *
 * Magellan's replies are a scripted demo (we can't reason yet); the founder's
 * input is real. Currency in USD ($) per the Magellan canon.
 * Ported from magellan-study-1-welcome.html + magellan-study-2-conversation.html.
 */

