type Run = { t: string; c?: "good" | "b" | "em" };
type MagReply = { paras: Run[][]; offer?: { title: string } };
type Msg =
  | { role: "you"; text: string; time: string }
  | { role: "mag"; reply: MagReply; time: string };

/* Scripted Magellan replies — play in order as the founder sends. */
const SCRIPT: MagReply[] = [
  {
    paras: [
      [
        { t: "Short version: the growth is real, but it's getting eaten before it reaches you. I pulled the last 90 days — revenue is up " },
        { t: "41% year over year", c: "good" },
        { t: ", but contribution margin is only up " },
        { t: "12%", c: "good" },
        { t: ". That gap is the whole story." },
      ],
      [
        { t: "And almost all of it is " },
        { t: "shipping", c: "b" },
        { t: ". It's running at 9% of revenue and climbing, while your COGS has stayed flat and healthy." },
      ],
    ],
  },
  {
    paras: [
      [
        { t: "That's the instinct most founders have, and it's wrong here. Your COGS is " },
        { t: "48% and stable", c: "b" },
        { t: " — and the new cake line is actually " },
        { t: "above", c: "em" },
        { t: " average at 54% margin even with the saffron. The leak isn't what you sell. It's what it costs to get it across the city." },
      ],
      [
        { t: "Three things stack up: small orders under $1,200 ship at a loss after last-mile, inbound freight isn't consolidated so you're paying per-shipment, and your free-ship threshold hasn't moved since 2023 while last-mile costs have." },
      ],
    ],
  },
  {
    paras: [
      [{ t: "In order of impact, not effort:" }],
      [
        { t: "One", c: "b" },
        { t: " — consolidate inbound freight to twice-weekly batched shipments. Biggest single lever, roughly " },
        { t: "$18K/month", c: "good" },
        { t: ", and it costs you nothing but a conversation with the supplier." },
      ],
      [
        { t: "Two", c: "b" },
        { t: " — raise the free-ship floor from $1,200 to $1,500. Your order data says ~18% of small orders will add an item to qualify, the rest start covering their own shipping." },
      ],
      [
        { t: "Three", c: "b" },
        { t: " — re-quote last-mile. You've been with the same rate card for two years; you have the volume now to negotiate." },
      ],
      [{ t: "If you do nothing else, do the first one. Want me to draft the note to the supplier so you can fire it off today?" }],
    ],
    offer: { title: "Draft the freight consolidation note" },
  },
];

const FALLBACK: MagReply = {
  paras: [
    [
      { t: "Good question. I'd pull the latest numbers before answering that for real — but the shape is the same: find where money leaks between revenue and what reaches you, and pull the biggest lever first." },
    ],
  ],
};

const fmtTime = () =>
  new Date().toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });

/* ─────────── shared composer ─────────── */
function Composer({
  placeholder,
  value,
  onChange,
  onSend,
  listening,
  onToggleListen,
  autoFocus,
}: {
  placeholder: string;
  value: string;
  onChange: (v: string) => void;
  onSend: () => void;
  listening: boolean;
  onToggleListen: () => void;
  autoFocus?: boolean;
}) {
  return (
    <div className="study-input-card">
      <input
        className="study-input-field"
        placeholder={placeholder}
        autoFocus={autoFocus}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            onSend();
          }
        }}
      />
      <div className="study-input-row">
        <button className="study-input-btn" title="Attach" type="button">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" />
          </svg>
        </button>
        <span className="study-input-spacer" />
        <button
          className={`study-input-talk${listening ? " listening" : ""}`}
          title="Voice conversation"
          aria-label="Voice conversation"
          aria-pressed={listening}
          type="button"
          onClick={onToggleListen}
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <line x1="6" y1="9" x2="6" y2="15" />
            <line x1="10" y1="6" x2="10" y2="18" />
            <line x1="14" y1="4" x2="14" y2="20" />
            <line x1="18" y1="7" x2="18" y2="17" />
          </svg>
        </button>
        <button className="study-input-mic" title="Hold to talk" type="button">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z" />
            <path d="M19 10v2a7 7 0 01-14 0v-2" />
            <line x1="12" y1="19" x2="12" y2="23" />
            <line x1="8" y1="23" x2="16" y2="23" />
          </svg>
        </button>
        <button className="study-input-send" title="Send" type="button" onClick={onSend}>
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
            <line x1="12" y1="19" x2="12" y2="5" />
            <polyline points="5 12 12 5 19 12" />
          </svg>
        </button>
      </div>
    </div>
  );
}

function MagBody({ reply, onOffer }: { reply: MagReply; onOffer: () => void }) {
  return (
    <div className="study-msg-body">
      {reply.paras.map((para, pi) => (
        <p key={pi}>
          {para.map((run, ri) =>
            run.c === "good" ? (
              <span key={ri} className="good">{run.t}</span>
            ) : run.c === "b" ? (
              <b key={ri}>{run.t}</b>
            ) : run.c === "em" ? (
              <em key={ri} className="em">{run.t}</em>
            ) : (
              <span key={ri}>{run.t}</span>
            )
          )}
        </p>
      ))}
      {reply.offer && (
        // The doorway to Build (the split canvas) — births the artifact.
        <button className="study-offer" type="button" title="Open the workbench" onClick={onOffer}>
          <span className="study-offer-i">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
              <path d="M4 4h16v16H4z" />
              <path d="M4 8h16" />
            </svg>
          </span>
          <span>
            <span className="study-offer-t" style={{ display: "block" }}>{reply.offer.title}</span>
            <span className="study-offer-s">Opens the workbench · nothing sends without you</span>
          </span>
        </button>
      )}
    </div>
  );
}

export default function StudyPage() {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [draft, setDraft] = useState("");
  const [thinking, setThinking] = useState(false);
  const [listening, setListening] = useState(false);
  const [greetPart, setGreetPart] = useState("Afternoon");
  const [building, setBuilding] = useState(false);
  const streamRef = useRef<HTMLDivElement>(null);

  // Time-of-day greeting (stable initial value → no hydration mismatch).
  useEffect(() => {
    const h = new Date().getHours();
    setGreetPart(
      h < 5 ? "Late night" : h < 12 ? "Morning" : h < 17 ? "Afternoon" : h < 22 ? "Evening" : "Late night"
    );
  }, []);

  // Keep the stream pinned to the latest message.
  useEffect(() => {
    const el = streamRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, [messages, thinking]);

  const started = messages.length > 0;
  const title = messages.find((m): m is Extract<Msg, { role: "you" }> => m.role === "you")?.text ?? "New conversation";

  const send = () => {
    const text = draft.trim();
    if (!text || thinking) return;
    const youCount = messages.filter((m) => m.role === "you").length;
    setMessages((m) => [...m, { role: "you", text, time: fmtTime() }]);
    setDraft("");
    setThinking(true);
    setTimeout(() => {
      setThinking(false);
      setMessages((m) => [...m, { role: "mag", reply: SCRIPT[youCount] ?? FALLBACK, time: fmtTime() }]);
    }, 950);
  };

  const newConversation = () => {
    setMessages([]);
    setDraft("");
    setThinking(false);
  };

  // Artifact born → fold-to-focus into the Build split canvas.
  if (building) return <StudyBuild onClose={() => setBuilding(false)} />;

  return (
    <div className={`study-canvas${started ? " thread" : ""}`}>
      <div className="study-ambient" />
      <div className="study-ghost-m" aria-hidden="true">
        <svg viewBox="0 0 252 182">
          <path fillRule="evenodd" d={GHOST_M_PATH} />
        </svg>
      </div>

      {!started ? (
        /* ── Cold open (the grand hall) ── */
        <div className="study-stage">
          <div className="study-greet">
            {greetPart}, <b>Johannes</b>.
          </div>
          <div className="study-subgreet">
            What&rsquo;s <span className="accent">our next move</span>?
          </div>
          <Composer
            placeholder="Talk to Magellan, or describe something to build…"
            value={draft}
            onChange={setDraft}
            onSend={send}
            listening={listening}
            onToggleListen={() => setListening((v) => !v)}
            autoFocus
          />
        </div>
      ) : (
        /* ── Thread ── */
        <>
          <div className="study-topbar study-thread-in">
            <button className="study-tb-icon" title="Past conversations" type="button">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <path d="M3 12a9 9 0 1 0 3-6.7" />
                <polyline points="3 4 3 9 8 9" />
                <polyline points="12 7 12 12 15 14" />
              </svg>
            </button>
            <div>
              <div className="study-tb-title">{title}</div>
              <div className="study-tb-meta">Strategy · just you and Magellan</div>
            </div>
            <div className="study-tb-spacer" />
            <button className="study-tb-icon" title="Save to memory" type="button">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
              </svg>
            </button>
            <button className="study-tb-icon" title="New conversation" type="button" onClick={newConversation}>
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor">
                <line x1="12" y1="5" x2="12" y2="19" />
                <line x1="5" y1="12" x2="19" y2="12" />
              </svg>
            </button>
          </div>

          <div className="study-stream study-thread-in" ref={streamRef}>
            <div className="study-stream-col">
              <div className="study-day">Today · {messages[0] && "time" in messages[0] ? messages[0].time : ""}</div>
              {messages.map((m, i) =>
                m.role === "you" ? (
                  <div key={i} className="study-msg-you">
                    {m.text}
                    <span className="t">{m.time}</span>
                  </div>
                ) : (
                  <div key={i} className="study-msg-mag">
                    <div className="study-msg-who">Magellan · {m.time}</div>
                    <MagBody reply={m.reply} onOffer={() => setBuilding(true)} />
                  </div>
                )
              )}
              {thinking && (
                <div className="study-msg-mag">
                  <div className="study-msg-who">Magellan</div>
                  <div className="study-thinking" aria-label="Magellan is thinking">
                    <span /><span /><span />
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="study-dock study-thread-in">
            <div className="study-dock-inner">
              <Composer
                placeholder="Keep going, or ask Magellan to make something…"
                value={draft}
                onChange={setDraft}
                onSend={send}
                listening={listening}
                onToggleListen={() => setListening((v) => !v)}
                autoFocus
              />
              <div className="study-dock-foot">Nothing here has made anything yet — it&rsquo;s just thinking</div>
            </div>
          </div>
        </>
      )}
    </div>
  );
}
